func RunRow(root, name string) (CaseResult, error) {
        profile := ProfileFor(name)
        radius, _ := LoadRadius(root, name)
        if radius == 0 {
                radius = profile.Radius
        }
        base, err := LoadLayout(root, name)
        if err != nil {
